 31	
 32	import { AttachmentTypes } from '../attachments';
 33	import { getRequestInitWithAuthHeader } from '../hooks/useAuth';
 34	import { useBoolean } from '../hooks/useBoolean';
 35	import { useLocationContext } from '../hooks/useLocationContext';
 36	import { attachmentSet } from '../redux-actions';
 37	import { State } from '../redux-reducers';
 38	import AttachEventsModal from './AttachEventsModal';
 39	import AttachLogModal from './AttachLogModal';
 40	import ResourceIcon from './ResourceIcon';
 41	
 42	const ALERTS_ENDPOINT = '/api/prometheus/api/v1/rules?type=alert';
 43	
 44	// Managed clusters have an additional info object that lives in a namespace whose name matches the cluster name
 45	const fetchManagedClusterInfo = async (clusterName: string): Promise<K8sResourceKind> => {
 46	  const endpoint = `/api/kubernetes/apis/internal.open-cluster-management.io/v1beta1/namespaces/${clusterName}/managedclusterinfos/${clusterName}`;
 47	  const response = await consoleFetchJSON(endpoint, 'get', getRequestInitWithAuthHeader());
 48	  return response;
 49	};
