 51	// Sanity check on the upload file size
 52	const MAX_FILE_SIZE_MB = 1;
 53	
 54	type FileUploadSelectOptionProps = {
 55	  setError: (error: string) => void;
 56	};
 57	
 58	const FileUploadSelectOption: React.FC<FileUploadSelectOptionProps> = ({ setError }) => {
 59	  const { t } = useTranslation('plugin__lightspeed-console-plugin');
 60	
 61	  const dispatch = useDispatch();
 62	
 63	  const fileInput = React.useRef(null);
 64	
 65	  const onClick = () => {
 66	    fileInput.current.click();
 67	  };
 68	
 69	  const onChange = React.useCallback(
 70	    (e) => {
 71	      const file = e.target.files[0];
 72	      if (!file) {
 73	        return;
 74	      }
 75	      if (file.size > MAX_FILE_SIZE_MB * 1024 * 1024) {
 76	        setError(
 77	          t('Uploaded file is too large. Max size is {{max}} MB.', { max: MAX_FILE_SIZE_MB }),
 78	        );
 79	        return;
 80	      }
 81	      setError(undefined);
 82	
 83	      const reader = new FileReader();
 84	      reader.onload = (event) => {
 85	        try {
 86	          const yaml = event.target.result as string;
 87	          const content = loadYAML(yaml);
 88	          if (typeof content !== 'object') {
 89	            setError(t('Uploaded file is not valid YAML'));
 90	            return;
 91	          }
 92	          const name = content.metadata?.name;
 93	          dispatch(
 94	            attachmentSet(
 95	              AttachmentTypes.YAML,
 96	              content.kind || '?',
 97	              name ? `${name} (${file.name})` : file.name,
 98	              undefined,
 99	              content.metadata?.namespace,
100	              yaml,
101	            ),
102	          );
103	        } catch {
104	          setError(t('Uploaded file is not valid YAML'));
105	        }
106	      };
107	      reader.readAsText(file);
108	    },
109	    [dispatch, setError, t],
110	  );
111	
112	  return (
113	    <SelectOption onClick={onClick} value={AttachmentTypes.YAMLUpload}>
114	      <FileUploadIcon /> {t('Upload from computer')}
115	      <input
116	        accept=".yaml,.yml"
117	        onChange={onChange}
118	        ref={fileInput}
119	        style={{ display: 'none' }}
120	        type="file"
121	      />
122	    </SelectOption>
123	  );
124	};
125	
126	const FilteredYAMLInfo = () => {
127	  const { t } = useTranslation('plugin__lightspeed-console-plugin');
128	
129	  return (
130	    <Tooltip content={t('Kind, Metadata, and Status sections only')}>
131	      <span className="ols-plugin__inline-icon">
132	        <InfoCircleIcon />
133	      </span>
134	    </Tooltip>
135	  );
136	};
137	
138	const AttachMenu: React.FC = () => {
139	  const { t } = useTranslation('plugin__lightspeed-console-plugin');
140	
141	  const dispatch = useDispatch();
142	
143	  const events = useSelector((s: State) => s.plugins?.ols?.get('contextEvents'));
144	  const isEventsLoading = useSelector((s: State) => s.plugins?.ols?.get('isContextEventsLoading'));
145	
146	  const [error, setError] = React.useState<string>();
147	  const [isEventsModalOpen, , openEventsModal, closeEventsModal] = useBoolean(false);
148	  const [isLogModalOpen, , openLogModal, closeLogModal] = useBoolean(false);
149	  const [isLoading, , setLoading, setLoaded] = useBoolean(false);
150	  const [isOpen, toggleIsOpen, , close, setIsOpen] = useBoolean(false);
151	
152	  const [kind, name, namespace] = useLocationContext();
153	
154	  const k8sContext = useK8sWatchResource<K8sResourceKind>(
155	    kind && kind !== 'Alert' && name ? { isList: false, kind, name, namespace } : null,
156	  );
157	
158	  const [context] = kind === 'Alert' && name ? [] : k8sContext;
159	
160	  const onSelect = React.useCallback(
161	    (_e: React.MouseEvent | undefined, attachmentType: string) => {
162	      if (attachmentType === AttachmentTypes.Events) {
163	        openEventsModal();
164	        close();
165	      } else if (attachmentType === AttachmentTypes.Log) {
166	        openLogModal();
167	        close();
168	      } else if (kind === 'Alert') {
169	        setLoading();
170	        const labels = Object.fromEntries(new URLSearchParams(location.search));
171	        consoleFetchJSON(ALERTS_ENDPOINT)
172	          .then((response) => {
173	            let alert;
174	            each(response?.data?.groups, (group) => {
175	              each(group.rules, (rule) => {
176	                alert = rule.alerts?.find((a) => isMatch(labels, a.labels));
177	                if (alert) {
178	                  return false;
179	                }
180	              });
181	              if (alert) {
182	                return false;
183	              }
184	            });
185	            if (alert) {
186	              try {
187	                const yaml = dumpYAML(alert, { lineWidth: -1 }).trim();
188	                dispatch(
189	                  attachmentSet(AttachmentTypes.YAML, kind, name, undefined, namespace, yaml),
190	                );
191	                close();
192	              } catch (e) {
193	                setError(t('Error converting to YAML: {{e}}', { e }));
194	              }
195	            } else {
196	              setError(t('Failed to find definition YAML for alert'));
197	            }
198	            setLoaded();
199	          })
200	          .catch((err) => {
201	            setError(t('Error fetching alerting rules: {{err}}', { err }));
202	            setLoaded();
203	          });
204	      } else if (
205	        // Only show this attachment option when the object in play is a ManagedCluster
206	        kind === 'cluster.open-cluster-management.io~v1~ManagedCluster' &&
207	        attachmentType === AttachmentTypes.YAML
208	      ) {
209	        setLoading();
210	
211	        // First attach the ManagedCluster object
212	        if (context) {
213	          const clusterData = cloneDeep(context);
214	          delete clusterData.metadata.managedFields;
215	          try {
216	            const clusterYaml = dumpYAML(clusterData, { lineWidth: -1 }).trim();
217	            dispatch(
218	              attachmentSet(AttachmentTypes.YAML, kind, name, undefined, namespace, clusterYaml),
219	            );
220	          } catch (e) {
221	            setError(t('Error converting ManagedCluster to YAML: {{e}}', { e }));
222	            setLoaded();
223	            return;
224	          }
225	        }
226	
227	        // Then fetch and attach the ManagedClusterInfo object
228	        fetchManagedClusterInfo(name)
229	          .then((clusterInfo) => {
230	            const data = cloneDeep(clusterInfo);
231	            delete data.metadata.managedFields;
232	            try {
233	              const yaml = dumpYAML(data, { lineWidth: -1 }).trim();
234	              dispatch(
235	                attachmentSet(
236	                  AttachmentTypes.YAML,
237	                  'ManagedClusterInfo',
238	                  name,
239	                  undefined,
240	                  name,
241	                  yaml,
242	                ),
243	              );
244	              close();
245	            } catch (e) {
246	              setError(t('Error converting ManagedClusterInfo to YAML: {{e}}', { e }));
247	            }
248	            setLoaded();
249	          })
250	          .catch((err) => {
251	            setError(t('Error fetching cluster info: {{err}}', { err }));
252	            setLoaded();
253	          });
254	      } else if (
255	        context &&
256	        (attachmentType === AttachmentTypes.YAML || attachmentType === AttachmentTypes.YAMLFiltered)
257	      ) {
258	        const data = cloneDeep(
259	          attachmentType === AttachmentTypes.YAMLFiltered
260	            ? { kind: context.kind, metadata: context.metadata, status: context.status }
261	            : context,
262	        );
263	        // We ignore the managedFields section because it doesn't have much value
264	        delete data.metadata.managedFields;
265	        try {
266	          const yaml = dumpYAML(data, { lineWidth: -1 }).trim();
267	          dispatch(attachmentSet(attachmentType, kind, name, undefined, namespace, yaml));
268	          close();
269	        } catch (e) {
270	          setError(t('Error converting to YAML: {{e}}', { e }));
271	        }
272	      }
273	    },
274	    [
275	      close,
276	      context,
277	      dispatch,
278	      kind,
279	      name,
280	      namespace,
281	      openEventsModal,
282	      openLogModal,
283	      setLoaded,
284	      setLoading,
285	      t,
286	    ],
287	  );
288	
289	  const toggle = React.useCallback(
290	    (toggleRef: React.Ref<MenuToggleElement>) => (
291	      <Tooltip content={t('Attach context')} style={isOpen ? { visibility: 'hidden' } : undefined}>
292	        <div>
293	          <MenuToggle
294	            className="ols-plugin__attach-menu"
295	            isExpanded={isOpen}
296	            onClick={toggleIsOpen}
297	            ref={toggleRef}
298	            variant="plain"
299	          >
300	            <Icon size="md">
301	              <PlusCircleIcon
302	                className={isOpen ? 'ols-plugin__context-menu-icon--active' : undefined}
303	              />
304	            </Icon>
305	          </MenuToggle>
306	        </div>
307	      </Tooltip>
308	    ),
309	    [isOpen, t, toggleIsOpen],
310	  );
311	
312	  const showEvents =
313	    !!context &&
314	    [
315	      'CronJob',
316	      'DaemonSet',
317	      'Deployment',
318	      'DeploymentConfig',
319	      'HorizontalPodAutoscaler',
320	      'Job',
321	      'kubevirt.io~v1~VirtualMachine',
322	      'kubevirt.io~v1~VirtualMachineInstance',
323	      'Pod',
324	      'PodDisruptionBudget',
325	      'ReplicaSet',
326	      'ReplicationController',
327	      'StatefulSet',
328	    ].includes(kind);
329	
330	  const showLogs =
331	    !!context &&
332	    [
333	      'CronJob',
334	      'DaemonSet',
335	      'Deployment',
336	      'DeploymentConfig',
337	      'HorizontalPodAutoscaler',
338	      'Job',
339	      'kubevirt.io~v1~VirtualMachine',
340	      'kubevirt.io~v1~VirtualMachineInstance',
341	      'Pod',
342	      'PodDisruptionBudget',
343	      'ReplicaSet',
344	      'ReplicationController',
345	      'StatefulSet',
346	    ].includes(kind);
347	
348	  const isResourceContext = !!context && !!kind && !!name;
349	
350	  return (
351	    <>
352	      {showEvents && context && context.metadata?.uid && (
353	        <AttachEventsModal
354	          isOpen={isEventsModalOpen}
355	          kind={context.kind}
356	          name={name}
357	          namespace={namespace}
358	          onClose={closeEventsModal}
359	          uid={context.metadata?.uid}
360	        />
361	      )}
362	      {showLogs && (
363	        <AttachLogModal isOpen={isLogModalOpen} onClose={closeLogModal} resource={context} />
364	      )}
365	
366	      <Select isOpen={isOpen} onOpenChange={setIsOpen} onSelect={onSelect} toggle={toggle}>
367	        <SelectList className="ols-plugin__context-menu">
368	          <>
369	            {isResourceContext && (
370	              <>
371	                <Title className="ols-plugin__context-menu-heading" headingLevel="h5">
372	                  {t('Currently viewing')}
373	                </Title>
374	                <Label
375	                  className="ols-plugin__context-label"
376	                  textMaxWidth="10rem"
377	                  title={t('{{kind}} {{name}} in namespace {{namespace}}', {
378	                    kind,
379	                    name,
380	                    namespace,
381	                  })}
382	                >
383	                  <ResourceIcon kind={kind} /> {name}
384	                </Label>
385	              </>
386	            )}
387	
388	            <Title className="ols-plugin__context-menu-heading" headingLevel="h5">
389	              {t('Attach')}
390	            </Title>
391	
392	            {kind === 'Alert' ? (
393	              <SelectOption value={AttachmentTypes.YAML}>
394	                <FileCodeIcon /> {t('Alert')} {isLoading && <Spinner size="md" />}
395	              </SelectOption>
396	            ) : kind === 'cluster.open-cluster-management.io~v1~ManagedCluster' ? (
397	              <SelectOption value={AttachmentTypes.YAML}>
398	                <TaskIcon /> {t('Attach cluster info')}
399	                {isLoading && <Spinner size="md" />}
400	              </SelectOption>
401	            ) : (
402	              <>
403	                {isResourceContext && (
404	                  <>
405	                    <SelectOption value={AttachmentTypes.YAML}>
406	                      <FileCodeIcon /> Full YAML file
407	                    </SelectOption>
408	                    <SelectOption value={AttachmentTypes.YAMLFiltered}>
409	                      <FileCodeIcon /> Filtered YAML <FilteredYAMLInfo />
410	                    </SelectOption>
411	                  </>
412	                )}
413	                {showEvents && (
414	                  <div title={!isEventsLoading && events.length === 0 ? t('No events') : undefined}>
415	                    <SelectOption
416	                      isDisabled={!isEventsLoading && events.length === 0}
417	                      value={AttachmentTypes.Events}
418	                    >
419	                      <TaskIcon /> {t('Events')}
420	                    </SelectOption>
421	                  </div>
422	                )}
423	                {showLogs && (
424	                  <SelectOption value={AttachmentTypes.Log}>
425	                    <TaskIcon /> {t('Logs')}
426	                  </SelectOption>
427	                )}
428	              </>
429	            )}
430	            <FileUploadSelectOption setError={setError} />
431	          </>
432	
433	          {error && (
434	            <Alert
435	              className="ols-plugin__alert"
436	              isInline
437	              title={t('Failed to attach')}
438	              variant="danger"
439	            >
440	              {error}
441	            </Alert>
442	          )}
443	        </SelectList>
444	      </Select>
445	    </>
446	  );
447	};
448	
449	export default AttachMenu;

