161	    (_e: React.MouseEvent | undefined, attachmentType: SelectOptionProps['value']) => {
162	      if (attachmentType === AttachmentTypes.Events) {
163	        openEventsModal();
164	        close();
165	      } else if (attachmentType === AttachmentTypes.Log) {
166	        openLogModal();
167	        close();
