169	        setLoading();
170	        const labels = Object.fromEntries(new URLSearchParams(location.search));
171	        consoleFetchJSON(ALERTS_ENDPOINT)
172	          .then((response) => {
173	            let alert;
174	            each(response?.data?.groups, (group) => {
175	              each(group.rules, (rule) => {
176	                alert = rule.alerts?.find((a) => isMatch(labels, a.labels));
177	                if (alert) {
178	                  return false;
179	                }
180	              });
181	              if (alert) {
182	                return false;
183	              }
184	            });
